<template>
  <div>
    <div style="width: 100%; background-color: white; padding: 16px;">
      <h2>{{ data.contestantName }}</h2>
      <p style="margin-bottom: 0; font-size: 16px; color:blue">评委：{{ data.judgeName }}</p>
      <p style="font-size: 16px; color: green;">分组：{{ data.groupName }}</p>
      <div style="width: 100%" v-for="(item, index) in data.scoreDetails" :key="index">
        <a-divider style="margin: 12px 0;"/>
        <h2>{{ item.ruleName }}（{{ item.ruleMinScore }}-{{ item.ruleMaxScore }}分）</h2>
        <h3>得分：<span style="color: blue;">{{ item.score? item.score.toFixed(2) : '' }}</span> 分</h3>
      </div>
      <a-divider style="margin: 12px 0;"/>
      <h2>综合得分：<span style="color: blue;">{{ data.totalScore ? data.totalScore.toFixed(2) : '' }}</span> 分</h2>
      <h2>权重得分：<span style="color: blue;">{{ data.weightedScore ? data.weightedScore.toFixed(2) : '' }}</span> 分</h2>
    </div>
  </div>
</template>
<script>
import { getJudgeContestantScoreDetail } from '@/api/scoreRecord'
export default {
  data() {
    return {
      data: {},
    }
  },
  mounted() {
    this.loadData()
  },
  methods: {
    loadData() {
      getJudgeContestantScoreDetail(this.$route.params.id, this.$route.params.cid, this.$route.params.judgeId).then(res => {
        this.data = res
      })
    },
  },
}
</script>
<style scoped lang="less">
@media only screen and (max-width: 767px) {
  h2, span {
    text-shadow: 0.3px 0 0 currentColor, -0.3px 0 0 currentColor, 0 0.3px 0 currentColor, 0 -0.3px 0 currentColor;
  }
}
</style>
